const { event, data } = context;
const cfg = cliaas.config;
if (event === 'ticket.created' && cfg.autoCreate) {
  cliaas.log.info(`Would create Jira issue in ${cfg.projectKey}: ${data.subject}`);
}
if (event === 'ticket.resolved' && cfg.syncStatus) {
  cliaas.log.info(`Would transition Jira issue to Done`);
}
